      "authenticator": "OIDC/JWT (AuthenticationConfiguration)",
      "condition": "config.AuthenticationConfig != nil",
      "implementation": "newJWTAuthenticator → oidc.New per JWT entry → tokenunion.NewFailOnError → WrapAudienceAgnosticToken; supports hot-reload via atomic.Pointer",
      "added_to": "tokenAuthenticators"
    },
    {
      "step": 8,
      "authenticator": "Webhook token",
      "condition": "len(config.WebhookTokenAuthnConfigFile) > 0",
      "implementation": "newWebhookTokenAuthenticator → webhook.New → tokencache.New",
      "added_to": "tokenAuthenticators"
    },
    {
