      "authenticator": "Bearer token union (wraps all tokenAuthenticators)",
      "condition": "len(tokenAuthenticators) > 0",
      "implementation": "tokenunion.New(tokenAuthenticators...) → optional tokencache.New → bearertoken.New + websocket.NewProtocolAuthenticator",
      "added_to": "authenticators"
